_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUv.xy - 0.5;
//vUv.x *= aspect_ratio;

float dist = length(vUv) * 3;
float angle = atan(vUv.y, vUv.x);
float t = uTime * 0.75;

vec3 color = 0;
for(int i=0; i<3; i++) {
    float fi = float(i)*0.3;
    float wave = sin(dist * 4 - t*4 + fi) * 0.5;
    wave += sin(angle*3 + t*2 + fi) * 0.3;
    wave += sin((dist*2 + angle*2) - t*3 + fi) * 0.2;

    color[i] = 0.7 / (0.1 + abs(wave)) * (1 - dist*0.3);
}

color = mix(color, color.gbr, sin(t)*0.3 + 0.3);
color *= .1 + uRms/22;

ret = vec4(color * (0.8 + 0.3*sin(t + vUv.x*5)),1);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
uv2 = vec2(.2/vRadius+uTime/4,vAngle/3.14)*2;
float mod = length(sin(uv2*3.141/2+uTime*.1));
vec2 noise = texture(sampler_noise_hq,uv2+mod).rg;
float mask = (noise.r <= sw2);
vec2 rohr = sw1*vRadius * (noise-.5) /2*mask;

uv1 = vec2(1-vUv.x,vUv.y);
ret =  GetPixel(vUv)+GetPixel(uv1);

vec3 back = .2*(.5+(vUv.x-.5)*q1+(vUv.y-.5)*q2);
vUv+= rohr * sw1;

uv1 = vec2(1-vUv.x,vUv.y);
ret += (GetBlur2(vUv) + GetBlur2(uv1)) *min(.5+audioHighSmooth/4,2) *(1+sw1) * clamp01(1-lum(ret)/2);
ret += !sw1*back;
ret = mix(ret*(hue_shader*2-1),ret,lum(ret));;
//ret = GetPixel(vUv);
//MilkDrop3 Color Mode:
ret /= vec3(-1.1,-2.0,2.8);
//MilkDrop3 Shadows Mode:
ret += pow(texture(sampler_main,vec2(vUv.x,1-vUv.y)).yyy+texture(sampler_main,1-vUv).yyy,vec3(1,2,3));
//MilkDrop3 Burn Mode:
ret = mix(ret,2,GetPixel(vUv).z*1.36);

  fragColor = ret;
}
